sql.where:
(t."IsDelete" = false OR t."IsDelete" IS NULL)

    AND mp."CountyDistrict" = #{countyDistrict}


    AND mp."Town" = #{town}


    AND mp."Village" = #{village}


    AND EXTRACT(YEAR FROM t."SamplingDate") = #{year}


    AND lower(btrim(t."SoilSamplingTime")) = lower(btrim(#{periodZh}))


    AND mp."TobaccoFieldType" = CAST(#{tobaccoFieldType} AS tobacco_field_type)

mapper.select:
SELECT MAX() FROM public."SoilDatas" t JOIN public."MonitoringPoints" mp ON mp."MonitoringPointID" = t."MonitoringPointID"
AND t."SoilAttribute"::text = #{attr}
AND t."SoilAttribute" = CAST(#{attr} AS soil_parameters)

SELECT MIN() FROM public."SoilDatas" t JOIN public."MonitoringPoints" mp ON mp."MonitoringPointID" = t."MonitoringPointID"
AND t."SoilAttribute"::text = #{attr}
AND t."SoilAttribute" = CAST(#{attr} AS soil_parameters)

